import time
import google.generativeai as genai

def analyze_video(path: str, query: str, model_name="gemini-1.5-pro") -> str:
    file = genai.upload_file(path)
    for _ in range(60):  # 5-minute max wait (60 * 5s)
        file = genai.get_file(file.name)
        if file.state.name == "ACTIVE":
            break
        if file.state.name == "FAILED":
            raise RuntimeError(f"Video processing failed: {file.name}")
        time.sleep(5)
    else:
        raise TimeoutError("Video processing timed out after 5 minutes")
    model = genai.GenerativeModel(model_name)
    return model.generate_content([query, file]).text

import google.generativeai as genai

model = genai.GenerativeModel(
    model_name="gemini-2.0-flash",
    tools=["code_execution"]
)

response = model.generate_content(
    "Calculate the first 20 Fibonacci numbers and show the result"
)

for part in response.candidates[0].content.parts:
    if hasattr(part, "executable_code"):
        print("Code:\n", part.executable_code.code)
    if hasattr(part, "code_execution_result"):
        print("Output:\n", part.code_execution_result.output)

